const { execFile } = require('child_process');

async function resizeImage(inputPath, outputPath, dimensions, effects = []) {
  return new Promise((resolve, reject) => {
    const args = ['convert', inputPath];

    // Add resize dimensions
    args.push('-resize', dimensions);

    // Apply special effects based on the 'effects' array
    if (effects.includes('grayscale')) {
      args.push('-colorspace', 'Gray');
    }
    if (effects.includes('sepia')) {
      // 80% is a common value for sepia tone
      args.push('-sepia', '80%');
    }
    if (effects.includes('blur')) {
      // Blur with radius 0 and sigma 2 (a light blur)
      args.push('-blur', '0x2');
    }
    if (effects.includes('enhance')) {
      // Automatically adjust image levels and gamma for enhancement
      args.push('-auto-gamma', '-auto-level');
    }

    // Add the output path as the last argument
    args.push(outputPath);

    // Execute the GraphicsMagick (gm) command
    // Ensure 'gm' is installed and available in your system's PATH
    execFile('gm', args, (error, stdout, stderr) => {
      if (error) {
        // Reject the promise if an error occurs during image processing
        return reject(new Error(`Image processing failed: ${error.message}\n${stderr}`));
      }
      // Resolve with the output path on success
      resolve(outputPath);
    });
  });
}